// First, get all products to understand categories
const productsResult = await external_queryTable({ table: 'products' });
const products = productsResult.rows as Array<{id: number; name: string; category: string; price: number}>;

// Get unique categories
const categories = Array.from(new Set(products.map(p => p.category)));
console.log('Categories found:', categories);

// Get all purchases with customer and product info
const purchasesResult = await external_queryTable({ table: 'purchases' });
const purchases = purchasesResult.rows as Array<{id: number; customer_id: number; product_id: number; quantity: number; total: number}>;

// Create a map of product_id to category
const productMap = new Map(products.map(p => [p.id, p.category]));

// Get all customers
const customersResult = await external_queryTable({ table: 'customers' });
const customers = customersResult.rows as Array<{id: number; name: string; email: string; city: string; joined: string}>;

// Track purchases by customer and category
const customerPurchases = new Map<number, {
  name: string;
  city: string;
  categories: Set<string>;
  spendByCategory: Map<string, number>;
}>();

for (const customer of customers) {
  customerPurchases.set(customer.id, {
    name: customer.name,
    city: customer.city,
    categories: new Set(),
    spendByCategory: new Map(categories.map(c => [c, 0]))
  });
}

// Process purchases
for (const purchase of purchases) {
  const category = productMap.get(purchase.product_id);
  if (category && customerPurchases.has(purchase.customer_id)) {
    const data = customerPurchases.get(purchase.customer_id)!;
    data.categories.add(category);
    data.spendByCategory.set(category, (data.spendByCategory.get(category) || 0) + purchase.total);
  }
}

// Filter customers who purchased from ALL categories
const qualifyingCustomers = Array.from(customerPurchases.entries())
  .filter(([_, data]) => data.categories.size === categories.length)
  .map(([id, data]) => ({
    id,
    name: data.name,
    city: data.city,
    spendByCategory: Object.fromEntries(data.spendByCategory)
  }));

console.log(`\nFound ${qualifyingCustomers.length} customer(s) who purchased from all ${categories.length} categories`);

return {
  categories,
  qualifyingCustomers
};
"}
